// Format LinkedIn escalations for SmartLead export
const contacts = $input.all();

const channelId = 'cc222222-3333-4444-5555-666677778888'; // SmartLead channel

// Build VALUES clause for batch insert
const values = contacts.map(c => 
  `('${c.json.campaign_contact_id}', '${channelId}', 'pending')`
).join(',\n  ');

return {
  json: {
    values: values,
    count: contacts.length,
    escalation_type: 'linkedin_to_email',
    contact_ids: contacts.map(c => ({
      contact_id: c.json.contact_id,
      campaign_contact_id: c.json.campaign_contact_id,
      email: c.json.email
    }))
  }
};

// Format phone escalations - create/update phone channel records
const contacts = $input.all();

const channelId = 'cc333333-4444-5555-6666-777788889999'; // Phone channel

// Build VALUES clause for batch insert/update
const values = contacts.map(c => 
  `('${c.json.campaign_contact_id}', '${channelId}', 'pending')`
).join(',\n  ');

// Format for call queue notification
const callQueue = contacts.map(c => ({
  name: `${c.json.first_name} ${c.json.last_name}`,
  company: c.json.company,
  phone: c.json.phone,
  email: c.json.email,
  engagement: c.json.engagement_level,
  last_opened: c.json.last_email_opened_at
}));

return {
  json: {
    values: values,
    count: contacts.length,
    escalation_type: 'email_to_phone',
    call_queue: callQueue,
    contact_ids: contacts.map(c => ({
      contact_id: c.json.contact_id,
      campaign_contact_id: c.json.campaign_contact_id,
      phone: c.json.phone
    }))
  }
};
